import { getSeriesWithOccurrences } from '@/lib/data-service';
import SubscribeButton from '@/components/SubscribeButton'; // We will create this in Step 3

export default async function SeriesPage({ params }: { params: { seriesKey: string } }) {
  const data = await getSeriesWithOccurrences(params.seriesKey);

  if (!data) {
    return <div className="p-20 text-center">Series Not Found.</div>;
  }

  return (
    <main className="max-w-4xl mx-auto p-8 font-sans bg-black min-h-screen text-white">
      <header className="mb-10 border-b border-gray-800 pb-6">
        <h1 className="text-4xl font-extrabold text-white mb-2">{data.canonicalName}</h1>
        <p className="text-lg text-gray-400 mb-6">
          Administered by the <span className="text-white font-semibold">{data.entityName}</span>
        </p>
        
        {/* --- The Notification Component --- */}
        <div className="bg-blue-900/30 border border-blue-800 p-8 rounded-2xl text-center">
          <h2 className="text-xl font-bold mb-2">Enable Lock-Screen Alerts</h2>
          <p className="text-blue-200/70 mb-6 text-sm">Get notified the moment a {data.seriesKey} date is verified.</p>
          <SubscribeButton />
        </div>
      </header>

      <section>
        <h2 className="text-2xl font-bold text-white mb-6">Verified Authority Records</h2>
        <div className="border border-gray-800 rounded-xl overflow-hidden bg-gray-900/50">
          <table className="w-full text-left">
            <thead className="bg-gray-800/50 border-b border-gray-800 text-gray-500 text-xs uppercase tracking-widest font-black">
              <tr>
                <th className="p-5">Event Date</th>
                <th className="p-5">Status</th>
                <th className="p-5 text-right">Evidence</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {data.occurrences.map((occ) => (
                <tr key={occ.id} className="hover:bg-gray-800/30 transition-colors">
                  <td className="p-5 font-mono text-blue-400">
                    {new Date(occ.date).toISOString().split('T')[0]}
                  </td>
                  <td className="p-5">
                    <span className="px-2 py-1 text-[10px] font-black rounded bg-green-900/50 text-green-400 uppercase tracking-tighter">
                      {occ.status}
                    </span>
                  </td>
                  <td className="p-5 text-right">
                    <a href={occ.verificationProof || '#'} target="_blank" className="text-xs text-gray-500 hover:text-white underline">
                      View Source
                    </a>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </main>
  );
}